const items = $input.all();
const results = [];
for (const item of items) {
  const asset = item.json;
  const subflows = [];
  if (['domain','subdomain'].includes(asset.asset_type)) subflows.push('dns', 'http');
  if (['web_app','api'].includes(asset.asset_type)) subflows.push('http', 'screenshot');
  if (asset.asset_type === 'ip') subflows.push('http');
  results.push({ json: { ...asset, subflows } });
}
return results;

